using Apex.Application.Abstractions.Data; using Apex.Application.Abstractions.Exceptions; using Apex.Application.Abstractions.Ids; using Apex.Application.Abstractions.Time; using Apex.Modules.Accounting.ChartOfAccounts.Domain; using Apex.Modules.Accounting.ChartOfAccounts.Repositories; using FluentValidation; using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.CreateAccountClass;
internal sealed record CreateAccountClassRequest(string Code,string Name); internal sealed record CreateAccountClassResponse(long Id,string Code,string Name,string Status);
internal sealed class CreateAccountClassValidator:AbstractValidator<CreateAccountClassRequest>{public CreateAccountClassValidator(){RuleFor(x=>x.Code).NotEmpty().MaximumLength(64);RuleFor(x=>x.Name).NotEmpty().MaximumLength(255);}}
internal sealed class CreateAccountClassHandler(IGeneralTransactionRunner tx,IAccountClassWriteRepository repo,IIdGenerator ids,IClock clock,IValidator<CreateAccountClassRequest> validator){public async Task<CreateAccountClassResponse> HandleAsync(CreateAccountClassRequest request,CancellationToken ct){await validator.ValidateAndThrowAsync(request,ct);CreateAccountClassResponse? result=null;await tx.ExecuteAsync(async token=>{var code=request.Code.Trim().ToUpperInvariant();if(await repo.CodeExistsAsync(code,ct:token))throw new ConflictException("Account class code already exists.",ChartOfAccountsErrors.CodeAlreadyExists);var value=AccountClass.Create(ids.NewId(),code,request.Name,clock.UtcNow);await repo.InsertAsync(value,token);result=new(value.Id,value.Code,value.Name,value.Status.ToDatabaseValue());},ct);return result!;}}
internal static class CreateAccountClassEndpoint{internal static RouteGroupBuilder MapCreateAccountClassEndpoint(this RouteGroupBuilder group){group.MapPost("/classes",async([FromBody]CreateAccountClassRequest request,[FromServices]CreateAccountClassHandler handler,CancellationToken ct)=>{var r=await handler.HandleAsync(request,ct);return Results.Created($"/api/v1/accounting/chart-of-accounts/classes/{r.Id}",r);}).WithName("CreateAccountClass");return group;}}
